final class GeneratedFixtureTests: XCTestCase {
    func testGeneratedRequiredNullableEncodesNullWhileOmittingOptionalNil() throws {
        let value = FixtureCreateSessionRequest(
            email: "me@example.com",
            verificationCode: "123456",
            requiredNullable: nil
        )

        let data = try NhostJSON.restEncoder.encode(value)
        let object = try XCTUnwrap(JSONSerialization.jsonObject(with: data) as? [String: Any])

        XCTAssertTrue(object["required_nullable"] is NSNull)
        XCTAssertNil(object["remember-me"])
    }

    func testGeneratedJSONMethodBuildsRequestAndDecodesResponse() async throws {
        let recorder = GeneratedFixtureRecorder()
        let transport = StubTransport { request in
            await recorder.record(request)
            return NhostRawResponse(
                status: 201,
                headers: ["content-type": "application/json"],
                body: Data(#"{"id":"session-1","createdAt":"2026-06-09T12:34:56Z","roles":["user"]}"#.utf8)
            )
        }
        let client = GeneratedFixtureClient(
            baseURL: try XCTUnwrap(URL(string: "https://auth.example.test/v1")),
            transport: transport
        )
        let requestedAt = try XCTUnwrap(NhostJSON.parse("2026-06-09T12:00:00Z"))

        let response = try await client.createSession(
            ticketId: "ticket/1",
            body: FixtureCreateSessionRequest(
                email: "me@example.com",
                verificationCode: "123456",
                requiredNullable: nil,
                rememberMe: true,
                metadata: ["source": .string("fixture")],
                requestedAt: requestedAt
            ),
            query: FixtureCreateSessionQuery(
                compact: FixturePostCompact(ownerId: "owner-1", active: true),
                filter: FixturePostFilter(ownerId: "owner-1", limit: 10),
                ids: ["a", "b"],
                include: ["profile", "roles"],
                redirectTo: "https://app.example.test/callback"
            ),
            headers: FixtureCreateSessionHeaders(ifMatch: ["etag-a", "etag-b"], xHasuraRole: "user")
        )

        let recordedRequest = await recorder.request()
        let request = try XCTUnwrap(recordedRequest)
        let body = try XCTUnwrap(request.body)
        let decodedBody = try NhostJSON.restDecoder.decode(FixtureCreateSessionRequest.self, from: body)
        let components = try XCTUnwrap(URLComponents(url: request.url, resolvingAgainstBaseURL: false))
        let queryItems = components.queryItems ?? []

        XCTAssertEqual(response.body.id, "session-1")
        XCTAssertEqual(response.status, 201)
        XCTAssertEqual(request.method, "POST")
        XCTAssertEqual(components.percentEncodedPath, "/v1/session/ticket%2F1")
        XCTAssertEqual(request.headers["accept"], "application/json")
        XCTAssertEqual(request.headers["content-type"], "application/json")
        XCTAssertEqual(request.headers["if-match"], "etag-a,etag-b")
        XCTAssertEqual(request.headers["x-hasura-role"], "user")
        XCTAssertEqual(decodedBody.email, "me@example.com")
        XCTAssertEqual(decodedBody.verificationCode, "123456")
        XCTAssertTrue(queryItems.contains(URLQueryItem(name: "compact", value: #"{"active":true,"owner-id":"owner-1"}"#)))
        XCTAssertTrue(queryItems.contains(URLQueryItem(name: "ids", value: "a,b")))
        XCTAssertTrue(queryItems.contains(URLQueryItem(name: "include[]", value: "profile")))
        XCTAssertTrue(queryItems.contains(URLQueryItem(name: "include[]", value: "roles")))
        XCTAssertTrue(queryItems.contains(URLQueryItem(name: "limit", value: "10")))
        XCTAssertTrue(queryItems.contains(URLQueryItem(name: "owner-id", value: "owner-1")))
    }

