    func testGeneratedBinaryRedirectAndHeaderOnlyErrorPaths() async throws {
        let recorder = GeneratedFixtureRecorder()
        let transport = StubTransport { request in
            await recorder.record(request)
            if request.method == "GET" {
                return NhostRawResponse(status: 200, headers: ["etag": "abc"], body: Data([0x01, 0x02]))
            }
            return NhostRawResponse(status: 401, headers: ["x-error": "missing"], body: Data())
        }
        let client = GeneratedFixtureClient(
            baseURL: try XCTUnwrap(URL(string: "https://storage.example.test")),
            transport: transport
        )

        let binary = try await client.downloadFile(id: "file 1", query: FixtureDownloadFileQuery(transform: "thumb"))
        XCTAssertEqual(binary.body, Data([0x01, 0x02]))
        XCTAssertEqual(binary.headers["etag"], "abc")

        let redirect = try client.verifyTicketURL(
            query: FixtureVerifyTicketQuery(redirectTo: "https://app.example.test/callback", ticket: "ticket-1")
        )
        XCTAssertEqual(
            redirect.absoluteString,
            "https://storage.example.test/verify?redirectTo=https%3A%2F%2Fapp.example.test%2Fcallback&ticket=ticket-1"
        )

        do {
            _ = try await client.exchangeToken(
                body: FixtureExchangeTokenBody(clientId: "client", refreshToken: "refresh")
            )
            XCTFail("Expected a FetchError.http error")
        } catch let FetchError.http(error) {
            XCTAssertEqual(error.status, 401)
            XCTAssertEqual(error.headers["x-error"], "missing")
            XCTAssertNil(error.body)
            XCTAssertEqual(error.rawBody, Data())
        }
    }

    func testGeneratedMultipartMethodUsesRawFieldNames() async throws {
        let recorder = GeneratedFixtureRecorder()
        let transport = StubTransport { request in
            await recorder.record(request)
            return NhostRawResponse(
                status: 200,
                headers: ["content-type": "application/json"],
