            )
        }
        let client = GeneratedFixtureClient(
            baseURL: try XCTUnwrap(URL(string: "https://storage.example.test")),
            transport: transport
        )

        let response = try await client.uploadFiles(
            body: FixtureUploadFilesBody(
                bucketId: "avatars",
                file: [Data([0x01])],
                metadata: [FixtureFileMetadata(fileId: "file-1", metadata: ["kind": .string("avatar")])]
            )
        )

        let recordedRequest = await recorder.request()
        let request = try XCTUnwrap(recordedRequest)
        let body = try XCTUnwrap(request.body)
        let bodyText = try XCTUnwrap(String(data: body, encoding: .utf8))

        XCTAssertEqual(response.body.processedFiles?.first?.fileId, "file-1")
        XCTAssertEqual(request.headers["accept"], "application/json")
        XCTAssertTrue(request.headers["content-type"]?.hasPrefix("multipart/form-data; boundary=") == true)
        XCTAssertTrue(bodyText.contains(#"name="bucket-id""#))
        XCTAssertTrue(bodyText.contains(#"name="file[]""#))
        XCTAssertTrue(bodyText.contains(#"name="metadata[]""#))
    }
